#nullable enable // autogenerated

using System;
using MVZ2Logic.Callbacks;
using MVZ2Logic.HeldItems;
using MVZ2Logic.Inputs;
using MVZ2Logic.Level.Components;
using PVZEngine;
using PVZEngine.Entities;
using PVZEngine.Level;
using PVZEngine.Definitions;
using PVZEngine.Models;
using PVZEngine.SeedPacks;

namespace MVZ2Logic.Level
{
    public static partial class LogicLevelExt
    {
        #region 手持物品
        public static IHeldItemComponent? GetHeldItemComponent(this LevelEngine level)
        {
            return level.GetComponent<IHeldItemComponent>();
        }
        public static void SetHeldItem(this LevelEngine level, IHeldItemBuilder builder)
        {
            var component = level.GetHeldItemComponent();
            if (component == null) return;
            component.SetHeldItem(builder);
        }
        public static void SetHeldItem(this LevelEngine level, NamespaceID type, int priority = 0, Action<IHeldItemBuilder>? action = null)
        {
            var builder = new HeldItemBuilder(type, priority);
            action?.Invoke(builder);
            SetHeldItem(level, builder);
        }
        public static void ResetHeldItem(this LevelEngine level)
        {
            var component = level.GetHeldItemComponent();
            if (component == null) return;
            component.ResetHeldItem();
        }
        public static bool CancelHeldItem(this LevelEngine level)
        {
            var component = level.GetHeldItemComponent();
            if (component == null) return false;
            return component.CancelHeldItem();
        }
        public static NamespaceID? GetHeldItemType(this LevelEngine level)
        {
            var data = level.GetHeldItemData();
            if (data == null)
                return null;
            return data.Type;
        }
        public static HeldItemDefinition? GetHeldItemDefinition(this LevelEngine level)
        {
            var data = level.GetHeldItemData();
            if (data == null)
                return null;
            return data.GetDefinition(level);
        }
        public static IHeldItemData? GetHeldItemData(this LevelEngine level)
        {
            var component = level.GetHeldItemComponent();
            if (component == null)
                return null;
            return component.Data;
        }
        public static HeldHighlight GetHeldHighlight(this LevelEngine level, IHeldItemTarget target, PointerData pointer)
        {
            var data = level.GetHeldItemData();
            var heldItemDef = level.GetHeldItemDefinition();
            if (data == null || heldItemDef == null)
                return HeldHighlight.None;
            return heldItemDef.GetHighlight(target, data, pointer);
        }
        public static void DoHeldItemPointerEvent(this LevelEngine level, IHeldItemTarget target, PointerInteractionData pointerParams)
        {
            var data = level.GetHeldItemData();
            var heldItemDef = level.GetHeldItemDefinition();
            if (data == null || heldItemDef == null)
                return;
            heldItemDef.DoPointerEvent(target, data, pointerParams);

            var args = new LogicLevelCallbacks.PostHeldItemEventParams(level, target, data, pointerParams);
            level.Triggers.RunCallbackFiltered(LogicLevelCallbacks.POST_HELD_ITEM_EVENT, args, heldItemDef.GetID());
        }
        public static IModelInterface? GetHeldItemModelInterface(this LevelEngine level)
        {
            var component = level.GetHeldItemComponent();
            if (component == null) return null;
            return component.GetHeldItemModelInterface();
        }
        public static bool ShouldHeldItemMakeEntityTwinkle(this LevelEngine level, Entity entity)
        {
            var heldDef = level.GetHeldItemDefinition();
            var heldItemData = level.GetHeldItemData();
            if (heldItemData == null || heldDef == null)
                return false;
            var behaviours = heldDef.GetBehaviours();
            foreach (var behaviour in behaviours)
            {
                if (behaviour is IHeldTwinkleEntityBehaviour twinkle && twinkle.ShouldMakeEntityTwinkle(entity, heldItemData))
                    return true;
            }
            return false;
        }
        public static bool IsHoldingExclusiveItem(this LevelEngine level)
        {
            if (!level.IsHoldingItem())
                return false;
            var holdingDefinition = level.GetHeldItemDefinition();
            if (holdingDefinition == null)
                return false;
            return holdingDefinition.Exclusive;
        }
        public static bool IsHoldingItem(this LevelEngine level)
        {
            var type = level.GetHeldItemType();
            return NamespaceID.IsValid(type) && type != LogicHeldTypes.none;
        }
        public static bool IsHoldingPickaxe(this LevelEngine level)
        {
            return level.GetHeldItemType() == LogicHeldTypes.pickaxe;
        }
        public static bool IsHoldingStarshard(this LevelEngine level)
        {
            return level.GetHeldItemType() == LogicHeldTypes.starshard;
        }
        public static bool IsHoldingTrigger(this LevelEngine level)
        {
            return level.GetHeldItemType() == LogicHeldTypes.trigger;
        }
        public static bool IsHoldingSword(this LevelEngine level)
        {
            return level.GetHeldItemType() == LogicHeldTypes.sword;
        }
        public static bool IsHoldingBlueprint(this LevelEngine level, SeedPack seedPack)
        {
            var data = level.GetHeldItemData();
            if (data == null)
                return false;
            return data.IsHoldingBlueprint(level, seedPack);
        }
        public static bool IsHoldingClassicBlueprint(this LevelEngine level, int i)
        {
            var data = level.GetHeldItemData();
            if (data == null)
                return false;
            return data.IsHoldingClassicBlueprint(i);
        }
        public static bool IsHoldingConveyorBlueprint(this LevelEngine level, int i)
        {
            var data = level.GetHeldItemData();
            if (data == null)
                return false;
            return data.IsHoldingConveyorBlueprint(i);
        }
        public static Entity? GetHoldingEntity(this LevelEngine level)
        {
            var data = level.GetHeldItemData();
            if (data == null)
                return null;
            return data.GetHoldingEntity(level);
        }
        public static bool IsHoldingEntity(this LevelEngine level, Entity entity)
        {
            return level.GetHoldingEntity() == entity;
        }
        #endregion
    }
}
